import React from 'react';
import { Pin, Trash2, Edit2, Eye, EyeOff } from 'lucide-react';
import './AnnouncementCard.css';

/**
 * AnnouncementCard Component
 * Displays individual announcement with actions
 */
export function AnnouncementCard({
  announcement,
  onEdit,
  onDelete,
  onPin,
  onTogglePublish,
  isAdmin = false,
  compact = false
}) {
  const getPriorityColor = (priority) => {
    switch (priority) {
      case 'Urgent':
        return 'priority-urgent';
      case 'Important':
        return 'priority-important';
      case 'Normal':
        return 'priority-normal';
      case 'Low':
        return 'priority-low';
      default:
        return 'priority-normal';
    }
  };

  const getAudienceColor = (audience) => {
    switch (audience) {
      case 'Students':
        return 'audience-students';
      case 'Teachers':
        return 'audience-teachers';
      case 'Parents':
        return 'audience-parents';
      case 'Staff':
        return 'audience-staff';
      default:
        return 'audience-all';
    }
  };

  const isExpired = announcement.expiryDate && new Date(announcement.expiryDate) < new Date();
  const isNotPublished = !announcement.isPublished;

  if (compact) {
    return (
      <div className={`announcement-card compact ${announcement.isPinned ? 'pinned' : ''} ${isExpired ? 'expired' : ''} ${isNotPublished ? 'draft' : ''}`}>
        <div className="card-content">
          <div className="card-header-compact">
            {announcement.isPinned && (
              <div className="pin-badge">
                <Pin className="icon" size={12} />
              </div>
            )}
            <h3 className="card-title-compact">{announcement.title}</h3>
          </div>
          <p className="card-description-compact">{announcement.description.substring(0, 100)}...</p>
          <div className="card-meta-compact">
            <span className={`priority-badge ${getPriorityColor(announcement.priority)}`}>
              {announcement.priority}
            </span>
            <span className={`audience-badge ${getAudienceColor(announcement.audience)}`}>
              {announcement.audience}
            </span>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className={`announcement-card ${announcement.isPinned ? 'pinned' : ''} ${isExpired ? 'expired' : ''} ${isNotPublished ? 'draft' : ''}`}>
      {/* Status Indicators */}
      {isExpired && <div className="status-expired">EXPIRED</div>}
      {isNotPublished && <div className="status-draft">DRAFT</div>}

      {/* Card Header */}
      <div className="card-header">
        <div className="header-left">
          {announcement.isPinned && (
            <div className="pin-icon" title="Pinned announcement">
              <Pin size={18} />
            </div>
          )}
          <div>
            <h3 className="card-title">{announcement.title}</h3>
            <p className="card-date">
              Published: {new Date(announcement.publishDate).toLocaleDateString()}
              {announcement.expiryDate && ` • Expires: ${new Date(announcement.expiryDate).toLocaleDateString()}`}
            </p>
          </div>
        </div>

        {/* Priority Badge */}
        <span className={`priority-badge ${getPriorityColor(announcement.priority)}`}>
          {announcement.priority}
        </span>
      </div>

      {/* Card Body */}
      <div className="card-body">
        <p className="card-description">{announcement.description}</p>
      </div>

      {/* Card Footer */}
      <div className="card-footer">
        <div className="footer-left">
          <span className={`audience-badge ${getAudienceColor(announcement.audience)}`}>
            {announcement.audience}
          </span>
        </div>

        {/* Actions */}
        {isAdmin && (
          <div className="card-actions">
            <button
              className="action-btn toggle-publish"
              onClick={() => onTogglePublish(announcement.id)}
              title={announcement.isPublished ? 'Unpublish' : 'Publish'}
            >
              {announcement.isPublished ? (
                <Eye size={18} />
              ) : (
                <EyeOff size={18} />
              )}
            </button>

            <button
              className="action-btn pin-btn"
              onClick={() => onPin(announcement.id)}
              title={announcement.isPinned ? 'Unpin' : 'Pin'}
            >
              <Pin size={18} />
            </button>

            <button
              className="action-btn edit-btn"
              onClick={() => onEdit(announcement)}
              title="Edit announcement"
            >
              <Edit2 size={18} />
            </button>

            <button
              className="action-btn delete-btn"
              onClick={() => onDelete(announcement.id)}
              title="Delete announcement"
            >
              <Trash2 size={18} />
            </button>
          </div>
        )}
      </div>
    </div>
  );
}
